import { execution } from '@dynatrace-sdk/automation-utils';
import { eventsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const timeFrameMs = parseInt(input.timeFrameMinutes) * 60 * 1000;
    const from = Date.now() - timeFrameMs;

    // Query for deployment events
    const response = await eventsClient.getEvents({
      eventSelector: `type(\"DEPLOYMENT\") AND entityId(\"${input.entityId}\")",
      from: from,
      to: Date.now()
    });

    const deployments = response.events
      .filter(e => e.eventType === 'DEPLOYMENT')
      .slice(0, parseInt(input.maxDeployments))
      .map(e => ({
        timestamp: e.startTime,
        version: e.properties?.version || 'unknown',
        status: e.properties?.status || 'unknown',
        description: e.title
      }));

    console.log(`Found ${deployments.length} deployments for ${input.entityId}`);

    return {
      entityId: input.entityId,
      deploymentCount: deployments.length,
      timeFrameMinutes: input.timeFrameMinutes,
      deployments: deployments
    };
  } catch (error) {
    console.error('Error retrieving deployments:', error);
    throw new Error(`Failed to retrieve deployments: ${error}`);
  }
}
